3	 * Every node kind is decorated — headings, paragraphs, list items, and
4	 * atoms all get the same tree-depth indentation and a consistent, prominent
5	 * marker, so the tree reads as one hierarchy regardless of how a node is
6	 * encoded in markdown. List items already have a native marker glyph
7	 * (bullet/number) and native hanging-indent positioning for it; rather than
8	 * replacing that mechanism, decorations.ts reuses it — the SAME
9	 * `padding-left`/`text-indent` pair Obsidian already uses to hang bullets
10	 * is applied uniformly (one fixed unit, not Obsidian's own per-level
11	 * values) to every kind, so list bullets/checkboxes hang correctly at our
12	 * depth-based position without needing separate positioning logic, and
13	 * kinds without a native marker (paragraphs, headings, atoms) get a
14	 * `::before` glyph that hangs the exact same way. No CM6 imports —
15	 * decorations.ts is a thin adapter.
16	 */
17	
18	import type { OutlineDoc, OutlineNode } from '../model';
19	import { isAtom } from '../model';
20	
21	export interface LineDecorationFact {
22	  /** 0-indexed absolute line number in the document. */
23	  readonly lineNumber: number;
24	  /** Distance from the document root; top-level nodes are depth 0. */
25	  readonly depth: number;
26	  /** True only for a node's own first line — carries the hang + marker. */
27	  readonly isFirstLine: boolean;
28	  /**
29	   * True for list-item first lines: they already have a native marker
30	   * glyph (bullet/number) that should be restyled in place, not
31	   * supplemented with our own `::before` marker.
32	   */
33	  readonly hasNativeMarker: boolean;
34	  /**
35	   * True for atom nodes (code/table/quote/callout/html/hr). `padding-left`
36	   * only shifts an element's own *content*, never its own border/background
37	   * box — invisible for plain text, but atoms render a visible background/
38	   * border box whose edges stay put regardless of padding. Atoms need
39	   * `margin-left` instead, which actually moves the box; decorations.ts
40	   * uses this flag to pick the right CSS property.
41	   */
42	  readonly isAtom: boolean;
43	}
44	
45	/**
46	 * Walks the parsed tree in document order (a node's own lines, then its
47	 * children — the same layout `nodeAtLine`/`startLine` assume: trailingGap
48	 * lines sit between a node's own lines and its children, and carry no fact
49	 * of their own).
50	 */
51	export function decorate(doc: OutlineDoc): LineDecorationFact[] {
52	  const facts: LineDecorationFact[] = [];
53	  let current = doc.preamble.length;
54	
55	  const walk = (node: OutlineNode, depth: number): void => {
56	    const atom = isAtom(node);
57	    for (let i = 0; i < node.lines.length; i++) {
58	      facts.push({
59	        lineNumber: current + i,
60	        depth,
61	        isFirstLine: i === 0,
62	        hasNativeMarker: node.kind === 'list-item' && i === 0,
63	        isAtom: atom,
64	      });
65	    }
66	    current += node.lines.length + node.trailingGap.length;
67	    node.children.forEach((child) => walk(child, depth + 1));
68	  };
69	
70	  doc.children.forEach((node) => walk(node, 0));
71	  return facts;
72	}
