/**
 * CM6 adapter for outline mode's visual node chrome: uniform tree-depth
 * indentation and a consistent marker across every node kind. A `ViewPlugin`
 * recomputes a `DecorationSet` from `decorate(parse(...))` on every view
 * update; all depth/marker logic lives in the pure decorate.ts module.
 * `refreshDecorations()` is the only transaction this module ever
 * dispatches, and it is content-empty — pure rendering, never a document
 * edit. See design.md D9/D10 for why every kind gets the same
 * `padding-left`/`text-indent` pair (Obsidian's own bullet-hanging
 * mechanism, reused rather than fought).
 */

import {
  Decoration,
  ViewPlugin,
  type DecorationSet,
  type EditorView,
  type ViewUpdate,
} from '@codemirror/view';
import { editorInfoField } from 'obsidian';
import { parse } from '../parse';
import { decorate } from './decorate';
import type { ModeSource } from './keymap';

function buildDecorations(view: EditorView, modes: ModeSource): DecorationSet {
  const info = view.state.field(editorInfoField, false);
  const path = info?.file?.path;
  if (!path || !modes.isOutline(path)) return Decoration.none;

  const doc = parse(view.state.doc.toString());
  const facts = decorate(doc);
  if (facts.length === 0) return Decoration.none;

  const lineCount = view.state.doc.lines;
  const decorations = facts
    .filter((fact) => fact.lineNumber < lineCount)
    .map((fact) => {
      const line = view.state.doc.line(fact.lineNumber + 1);
      // Atoms render a visible background/border box; padding-left only
      // shifts an element's own content, never that box, so atoms need
      // margin-left instead (see decorate.ts isAtom doc comment). No
      // hang/marker for atoms in v1 — their own chrome already reads as
      // "one thing," and hanging a marker into a background box is a
      // separate, unverified visual problem not worth the risk here.
      const classes = fact.isAtom ? ['to-node-atom'] : ['to-node-line'];
      if (fact.isFirstLine && !fact.isAtom) {
        classes.push('to-node-first');
        classes.push(fact.hasNativeMarker ? 'to-node-native-marker' : 'to-node-marker');
      }
      return Decoration.line({
        attributes: {
          class: classes.join(' '),
          style: `--to-depth: ${fact.depth}`,
        },
      }).range(line.from);
    });

  return Decoration.set(decorations, true);
}

// Views currently carrying the extension, so an out-of-band mode toggle
// (plugin data, not a CM6 transaction) can be surfaced: `EditorView` is
// handed to the ViewPlugin by CM6 itself (a standard, fully public pattern),
// and `view.dispatch({})` is documented public API — no Obsidian internals.
const activeViews = new Set<EditorView>();

export function decorationsExtension(modes: ModeSource) {
  return ViewPlugin.fromClass(
    class {
      decorations: DecorationSet;

      constructor(private readonly view: EditorView) {
        activeViews.add(view);
        this.decorations = buildDecorations(view, modes);
      }

      // Recompute on every view update, not just docChanged: mode toggles
      // arrive via refreshDecorations()'s empty dispatch, which is still a
      // ViewUpdate but carries no document change.
      update(update: ViewUpdate): void {
        this.decorations = buildDecorations(update.view, modes);
      }

      destroy(): void {
        activeViews.delete(this.view);
      }
    },
    {
      decorations: (plugin) => plugin.decorations,
    },
  );
}

/**
 * Force every live outline-decorated view to recompute. Outline mode lives
 * in plugin data, entirely outside CM6 state, so toggling it produces no
 * transaction on its own — call this right after a toggle so the change is
 * visible immediately instead of waiting for the next incidental edit.
 */
export function refreshDecorations(): void {
  for (const view of activeViews) view.dispatch({});
}

