1	/* Outline mode node chrome: one consistent indentation unit and marker
2	   style across every node kind (headings, paragraphs, list items, code/
3	   table/quote/callout/hr blocks).
4	
5	   The mechanism: Obsidian already positions list bullets/checkboxes via a
6	   hanging-indent pair — text-indent: -Npx (pulls the first line's inline
7	   content, bullet included, left of the padding edge) + padding-left: Npx
8	   (where wrapped/continuation lines actually start), with N growing
9	   per raw list-nesting level. Overriding only one half of that pair (an
10	   earlier attempt) broke it outright. Here we own BOTH halves, uniformly,
11	   for every text-flow kind: padding-left: depth * --to-indent-unit,
12	   text-indent: -1 * --to-hang, applied together to every decorated line.
13	   That's the same mechanism Obsidian's own list bullets use, just driven
14	   by our tree depth instead of raw markdown nesting — so a `::before`
15	   marker glyph (for kinds with no native marker) hangs exactly the same
16	   way a native bullet does, no absolute-position math required. List
17	   items keep their own native bullet/number glyph and positioning; its
18	   glyph is restyled here, not its position.
19	
20	   Atoms (code/table/quote/callout/html/hr) are a separate case: padding-
21	   left only shifts an element's own *content*, never its own border/
22	   background box, and atoms render a visible box whose edges would
23	   otherwise stay put regardless of padding (verified: a code fence's
24	   background box did not move even though its text did). margin-left
25	   actually moves the box, so atoms get that instead — no hang/marker,
26	   just indentation, since their own chrome already reads as "one thing."
27	
28	   --to-indent-unit/--to-hang are fixed rem values, not Obsidian's em-based
29	   --list-indent: em resolves against each line's OWN font size, and
30	   headings render at a larger font than paragraphs, so the same tree depth
31	   would otherwise draw a different pixel offset depending on which kind
32	   happened to sit at that depth. rem is root-relative and stays fixed.
33	
34	   padding-left/text-indent/margin-left need !important: Obsidian's own
35	   line styling sets these via an equal-or-higher-specificity rule later
36	   in the cascade (verified: without !important the rule was silently
37	   overridden even on lines with no competing native value of their own). */
38	
39	:root {
40		--to-indent-unit: 1.5rem;
41		--to-hang: 1.25rem;
42	}
43	
44	.cm-editor .cm-line.to-node-line {
45		padding-left: calc(var(--to-depth, 0) * var(--to-indent-unit)) !important;
46	}
47	
48	.cm-editor .cm-line.to-node-atom {
49		margin-left: calc(var(--to-depth, 0) * var(--to-indent-unit)) !important;
50	}
51	
52	.cm-editor .cm-line.to-node-first {
53		text-indent: calc(-1 * var(--to-hang)) !important;
54	}
55	
56	.cm-editor .cm-line.to-node-marker::before {
57		content: '\25CF'; /* ● filled circle — a deliberately prominent, fat marker */
58		display: inline-block;
59		width: var(--to-hang);
60		text-align: center;
61		color: var(--text-muted);
62		font-size: 0.6em;
63		vertical-align: middle;
64	}
65	
66	/* List markers (bullet "-"/"*" and ordered "1."/"2.") keep Obsidian's own
67	   glyph and native position — only resized/bolded in place, not replaced
68	   or repositioned. A replace-with-a-round-dot attempt (via ::after +
69	   position:absolute) was tried and reverted: Obsidian's fold-indicator
70	   chevron (rendered for any list item that has children — a fixed-size
71	   element independent of our indentation scheme) collided with the
72	   repositioned dot, and manual pixel offsets to dodge it ended up
73	   overlapping the marker with the item's own text instead — worse than
74	   the original mismatch. Matching the native bullet's *shape* to our own
75	   marker is a cosmetic follow-up, not attempted further here; resizing
76	   in place is safe because it never moves anything, so it can't collide
77	   with fold indicators or text. */
78	.cm-editor .cm-line.to-node-native-marker .list-bullet,
79	.cm-editor .cm-line.to-node-native-marker .list-number {
80		font-weight: 700;
81		font-size: 1.15em;
82		color: var(--text-muted);
83	}
84

