26	
27	const CONFLICTING_PLUGINS = ['obsidian-outliner', 'obsidian-zoom'];
28	
29	export default class TrueOutlinerPlugin extends Plugin {
30	  private data: PluginData = { ...DEFAULT_DATA };
31	  private registry!: OutlineModeRegistry;
32	
33	  override async onload(): Promise<void> {
34	    this.data = { ...DEFAULT_DATA, ...((await this.loadData()) as Partial<PluginData> | null) };
35	    this.registry = new OutlineModeRegistry(async (paths) => {
36	      this.data.outlinePaths = paths;
37	      await this.saveData(this.data);
38	    });
39	    this.registry.hydrate(this.data.outlinePaths);
40	
41	    this.addCommand({
42	      id: 'toggle-outline-mode',
43	      name: 'Toggle outline mode',
44	      editorCheckCallback: (checking, _editor, ctx) => {
45	        const path = ctx.file?.path;
46	        if (!path) return false;
47	        if (!checking) void this.toggleMode(path);
48	        return true;
49	      },
50	    });
51	
52	    this.addStructuralCommand('indent-node', 'Indent node', indent);
53	    this.addStructuralCommand('outdent-node', 'Outdent node', outdent);
54	    this.addStructuralCommand('move-node-up', 'Move node up', moveUp);
55	    this.addStructuralCommand('move-node-down', 'Move node down', moveDown);
56	
57	    this.registerEvent(
58	      this.app.vault.on('rename', (file, oldPath) => {
59	        if (file instanceof TFile) void this.registry.handleRename(oldPath, file.path);
60	      }),
61	    );
62	    this.registerEvent(
63	      this.app.vault.on('delete', (file) => {
64	        if (file instanceof TFile) void this.registry.handleDelete(file.path);
65	      }),
66	    );
67	    this.registerEvent(
68	      this.app.workspace.on('editor-menu', (menu, _editor, info) => {
69	        const path = info.file?.path;
