/**
 * Node chrome decorations — automates the outline-decorations spec
 * (openspec/changes/outline-decorations/specs/outline-decorations/spec.md).
 *
 * Every node kind gets the same tree-depth indentation and a consistent,
 * prominent marker (design.md D9/D10): headings/paragraphs/atoms get our
 * own padding-left|margin-left plus a synthetic marker; list items keep
 * their native bullet/number glyph and hanging-indent mechanism, just
 * driven by our depth-based padding-left/text-indent pair instead of
 * Obsidian's own per-level values, with the glyph itself resized in place
 * (not replaced — a replace-with-a-dot attempt collided with Obsidian's
 * fold-indicator chevron and was reverted, see design.md D10).
 */

import { browser, expect } from '@wdio/globals';
import { obsidianPage } from 'wdio-obsidian-service';
import * as h from '../helpers.js';

const MIXED_NOTE = 'Scratch/decorations-mixed.md';
const MIXED_MD = [
  '# Top',
  '',
  '## Mid',
  '',
  '- item',
  '  - nested item',
  '',
  'Parent para.',
  '- Child para as list item.',
  '',
  '```js',
  'code line',
  '```',
  '',
].join('\n');

const FLAT_NOTE = 'Scratch/decorations-flat.md';
const FLAT_MD = 'First thought.\n\nSecond thought.\n\nThird thought.\n';

const TASK_NOTE = 'Scratch/decorations-tasks.md';
// The exact shape that broke in the field: a checkbox list under a plain
// top-level paragraph, mixed checked/unchecked items.
const TASK_MD = [
  'Errands before the heat sets in.',
  '',
  '- [x] picked up paint samples',
  '- [x] returned the library book',
  "- [ ] drop off the drill at Tom's",
  '',
].join('\n');

describe('decorations', function () {
  before(async function () {
    await obsidianPage.resetVault();
    await h.resetPluginState();
  });

  afterEach(async function () {
    await h.dismissNotices();
  });

  it('renders nothing off outline mode', async function () {
    await h.createNote(MIXED_NOTE, MIXED_MD);
    const decorations = await h.getLineDecorations();
    expect(decorations.every((d) => !d.hasIndent && !d.hasAtomIndent && !d.hasMarker)).toBe(
      true,
    );
  });

  it('applies immediately on toggle, with no reload and no edit', async function () {
    await h.openNote(MIXED_NOTE);
    await h.toggleOutlineMode();
    await h.waitForNotice('Outline mode on');
    await browser.pause(200); // let the dispatched empty transaction settle

    const decorations = await h.getLineDecorations();
    expect(decorations.some((d) => d.hasIndent || d.hasAtomIndent)).toBe(true);
  });

  it('decorates every kind with tree-depth-consistent indentation', async function () {
    const lines = MIXED_MD.split('\n');
    const paddings = await h.getComputedLinePaddings();
    const decorations = await h.getLineDecorations();
    const at = (text: string) => ({
      padding: paddings[lines.indexOf(text)],
      state: decorations[lines.indexOf(text)],
    });

    // Headings/paragraphs: padding-left scales with tree depth, synthetic marker.
    expect(at('# Top').padding?.paddingLeft).toBe('0px');
    expect(at('# Top').state).toMatchObject({ hasIndent: true, hasMarker: true, depth: 0 });
    expect(at('## Mid').padding?.paddingLeft).toBe('24px');
    expect(at('## Mid').state).toMatchObject({ hasIndent: true, hasMarker: true, depth: 1 });

    // List items: same padding-left unit as headings/paragraphs at the same
    // depth, but native marker (restyled in place), no synthetic marker.
    expect(at('- item').padding?.paddingLeft).toBe('48px');
    expect(at('- item').state).toMatchObject({
      hasIndent: true,
      hasMarker: false,
      hasNativeMarker: true,
      depth: 2,
    });
    expect(at('  - nested item').padding?.paddingLeft).toBe('72px');

    // Paragraph-adjacency: depth matches its list-item sibling exactly.
    expect(at('Parent para.').padding?.paddingLeft).toBe('48px');
    expect(at('Parent para.').state).toMatchObject({ hasMarker: true, depth: 2 });
    expect(at('- Child para as list item.').padding?.paddingLeft).toBe('72px');

    // Atoms: margin-left (not padding-left — see design.md D9), no marker.
    // Depth 2: a section child of "## Mid", sibling of "- item"/"Parent para.".
    const fenceOpen = at('```js');
    expect(fenceOpen.padding?.marginLeft).toBe('48px');
    expect(fenceOpen.state).toMatchObject({ hasAtomIndent: true, hasMarker: false, depth: 2 });
    expect(at('code line').padding?.marginLeft).toBe('48px');

    await h.toggleOutlineMode(); // leave it off for later tests
    await h.waitForNotice('Outline mode off');
  });

  it('makes a flat paragraph-only document read as nodes', async function () {
    await h.createNote(FLAT_NOTE, FLAT_MD);
    await h.toggleOutlineMode();
    await h.waitForNotice('Outline mode on');
    await browser.pause(200);

    const decorations = await h.getLineDecorations();
    const lines = FLAT_MD.split('\n');
    for (const text of ['First thought.', 'Second thought.', 'Third thought.']) {
      const state = decorations[lines.indexOf(text)];
      expect(state?.hasMarker).toBe(true);
      expect(state?.depth).toBe(0);
    }

    await h.toggleOutlineMode(); // leave it off for later tests
    await h.waitForNotice('Outline mode off');
  });

  it('checkbox task lines get depth-based indentation but no synthetic marker', async function () {
    await h.createNote(TASK_NOTE, TASK_MD);
    await h.toggleOutlineMode();
    await h.waitForNotice('Outline mode on');
    await browser.pause(200);

    const decorations = await h.getLineDecorations();
    const paddings = await h.getComputedLinePaddings();
    const lines = TASK_MD.split('\n');

    expect(decorations[lines.indexOf('Errands before the heat sets in.')]).toMatchObject({
      hasMarker: true,
      depth: 0,
    });
    for (const text of [
      '- [x] picked up paint samples',
      '- [x] returned the library book',
      "- [ ] drop off the drill at Tom's",
    ]) {
      const i = lines.indexOf(text);
      expect(decorations[i]).toMatchObject({
        hasIndent: true,
        hasMarker: false,
        hasNativeMarker: true,
        depth: 1,
      });
      expect(paddings[i]?.paddingLeft).toBe('24px');
    }

    await h.toggleOutlineMode(); // leave it off for later tests
    await h.waitForNotice('Outline mode off');
  });

  it('never mutates the document, cursor, or undo stack', async function () {
    await h.openNote(MIXED_NOTE);
    await h.toggleOutlineMode();
    await h.waitForNotice('Outline mode on');
    await browser.pause(200);
    expect((await h.getLineDecorations()).some((d) => d.hasIndent)).toBe(true);

    const before = await h.getBuffer();
    await h.setCursor(0, 0);
    await browser.pause(200);

    expect(await h.getBuffer()).toBe(before);
    expect(await h.getCursor()).toEqual({ line: 0, ch: 0 });
    // Undo should have nothing structural to undo from decoration rendering:
    // an undo attempt must not change the buffer at all.
    await h.keys.undo();
    await browser.pause(200);
    expect(await h.getBuffer()).toBe(before);

    await h.toggleOutlineMode(); // leave it off for later tests
    await h.waitForNotice('Outline mode off');
  });
});

